class Solution {
public:
    string mergeAlternately(string word1, string word2) {
        string result;
        int len1 = word1.length(), len2 = word2.length();
        int min_len = min(len1, len2);
        for (int i = 0; i < min_len; i++) {
            result += word1[i];
            result += word2[i];
        }
        if (len1 > len2) {
            result += word1.substr(min_len);
        } else {
            result += word2.substr(min_len);
        }
        return result;
    }
};
```

